 25→    /// <summary>
 26→    /// Kusto-backed Service Tree node lookup.
 27→    /// </summary>
 28→    public sealed class ServiceTreeKustoClient : IServiceTreeNodeLookup
 29→    {
 30→        private readonly ServiceTreeKustoOptions kustoOptions;
 31→        private readonly ILogger<ServiceTreeKustoClient> logger;
 32→        private readonly TokenCredential tokenCredential;
 33→        private readonly string tokenScope;
 34→        private readonly bool isConfigured;
 35→        private readonly int maxBatchSize;
 36→        private readonly int maxConcurrency = 4;
 37→
 38→        /// <summary>
 39→        /// Initializes a new instance of the <see cref="ServiceTreeKustoClient"/> class.
 40→        /// </summary>
 41→        /// <param name="kustoOptions">Kusto options.</param>
 42→        /// <param name="logger">Logger instance.</param>
 43→        /// <param name="credentialFactory">Credential factory for cross-tenant support.</param>
 44→        public ServiceTreeKustoClient(
 45→            ServiceTreeKustoOptions kustoOptions,
 46→            ILogger<ServiceTreeKustoClient> logger,
 47→            ICredentialFactory credentialFactory)
 48→        {
 49→            this.kustoOptions = kustoOptions ?? throw new ArgumentNullException(nameof(kustoOptions));
 50→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 51→
 52→            if (string.IsNullOrWhiteSpace(this.kustoOptions.ClusterUri)
 53→                || string.IsNullOrWhiteSpace(this.kustoOptions.Database))
 54→            {
 55→                this.logger.LogWarning("ServiceTreeKustoClient: Kusto cluster or database is not configured.");
 56→                this.isConfigured = false;
 57→                return;
 58→            }
 59→
 60→            this.tokenScope = this.ResolveTokenScope(this.kustoOptions);
 61→            if (string.IsNullOrWhiteSpace(this.tokenScope))
 62→            {
 63→                this.logger.LogWarning("ServiceTreeKustoClient: Token scope is not configured.");
 64→                this.isConfigured = false;
 65→                return;
 66→            }
 67→
 68→            this.tokenCredential = this.ResolveTokenCredential(credentialFactory);
 69→
 70→            this.maxBatchSize = this.kustoOptions.MaxBatchSize <= 0 ? 200 : this.kustoOptions.MaxBatchSize;
 71→            this.isConfigured = true;
 72→
 73→            this.logger.LogInformation(
 74→                "ServiceTreeKustoClient: Configured. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, TokenScope={TokenScope}.",
 75→                this.kustoOptions.ClusterUri,
 76→                this.kustoOptions.Database,
 77→                this.kustoOptions.HierarchyTableName,
 78→                this.tokenCredential.GetType().Name,
 79→                this.tokenScope);
 80→        }
 81→
 82→        /// <inheritdoc/>
 83→        public async Task<IReadOnlyDictionary<string, ServiceTreeNode>> GetHierarchyNodesByServiceIdsAsync(
 84→            IEnumerable<string> serviceIds,
 85→            CancellationToken cancellationToken)
 86→        {
 87→            var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
 88→            if (!this.isConfigured)
 89→            {
 90→                return results;
 91→            }
 92→
 93→            var uniqueIds = (serviceIds ?? Enumerable.Empty<string>())
 94→                .Where(id => !string.IsNullOrWhiteSpace(id))
 95→                .Select(id => id.Trim())
 96→                .Distinct(StringComparer.OrdinalIgnoreCase)
 97→                .ToList();
 98→
 99→            if (uniqueIds.Count == 0)
100→            {
101→                return results;
102→            }
103→
104→            var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
105→            using var semaphore = new SemaphoreSlim(this.maxConcurrency);
106→            var tasks = batches.Select(async batch =>
107→            {
108→                await semaphore.WaitAsync(cancellationToken);
109→                try
110→                {
111→                    var batchResults = await this.QueryHierarchyBatchAsync(batch, cancellationToken);
112→                    foreach (var pair in batchResults)
113→                    {
114→                        results[pair.Key] = pair.Value;
115→                    }
116→                }
117→                catch (OperationCanceledException)
118→                {
119→                    throw;
120→                }
121→                catch (Exception ex)
122→                {
123→                    this.logger.LogWarning(
124→                        ex,
125→                        "ServiceTreeKustoClient: Batch of {BatchCount} IDs failed; continuing with remaining batches.",
126→                        batch.Count);
127→                }
128→                finally
129→                {
130→                    semaphore.Release();
131→                }
132→            }).ToList();
133→
134→            await Task.WhenAll(tasks);
135→            return results;
136→        }
137→
138→        private static string EscapeKustoString(string value)
139→        {
140→            return value.Replace("'", "''", StringComparison.Ordinal);
141→        }
142→
143→        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryHierarchyBatchAsync(
144→            IReadOnlyList<string> batch,
145→            CancellationToken cancellationToken)
146→        {
147→            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
148→            if (batch.Count == 0)
149→            {
150→                return results;
151→            }
152→
153→            // Build a fast-lookup set of the (already-lowercased) input IDs so we can
154→            // cross-key results by whichever hierarchy column matched each row.
155→            var batchSet = new HashSet<string>(
156→                batch.Select(id => id.ToLowerInvariant()),
157→                StringComparer.OrdinalIgnoreCase);
158→
159→            var hierarchyTable = this.NormalizeIdentifier(this.kustoOptions.HierarchyTableName);
160→            var builder = new StringBuilder();
161→            builder.AppendLine("let ids = datatable(TargetId:string)[");
162→            builder.Append(string.Join(", ", batch.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
163→            builder.AppendLine("];");
164→            builder.AppendLine($"{hierarchyTable}");
165→            builder.AppendLine("| where tolower(ServiceId) in (ids)");
166→            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
167→            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
168→            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
169→            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
170→            builder.AppendLine("| project");
171→            builder.AppendLine("    Id = tostring(ServiceId),");
172→            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
173→            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
174→            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
175→            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
176→            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
177→            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
178→            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
179→            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
180→            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
181→            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
182→            var query = builder.ToString();
183→
184→            var requestProperties = new ClientRequestProperties();
185→            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeHierarchy.{Guid.NewGuid():N}";
186→
187→            try
188→            {
189→                this.logger.LogInformation(
190→                    "ServiceTreeKustoClient: Executing hierarchy query for {BatchCount} IDs against {Cluster}/{Database}/{Table}.",
191→                    batch.Count,
192→                    this.kustoOptions.ClusterUri,
193→                    this.kustoOptions.Database,
194→                    this.kustoOptions.HierarchyTableName);
195→
196→                using var provider = this.CreateQueryProvider();
197→                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
198→
199→                do
200→                {
201→                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
202→                    if (idOrdinal < 0)
203→                    {
204→                        continue;
205→                    }
206→
207→                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
208→                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
209→                    var teamGroupIdOrdinal = this.TryGetOrdinal(reader, "TeamGroupId");
210→                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
211→                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
212→                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
213→                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
214→                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
215→                    var divisionNameOrdinal = this.TryGetOrdinal(reader, "DivisionName");
216→
217→                    while (reader.Read())
218→                    {
219→                        var id = this.ReadString(reader, idOrdinal);
220→                        if (string.IsNullOrWhiteSpace(id))
221→                        {
222→                            continue;
223→                        }
224→
225→                        var node = new ServiceTreeNode
226→                        {
227→                            Id = id,
228→                            Name = this.ReadString(reader, nameOrdinal),
229→                            Level = this.ReadString(reader, levelOrdinal),
230→                            ServiceGroupId = this.ReadString(reader, serviceGroupIdOrdinal),
231→                            ServiceGroupName = this.ReadString(reader, serviceGroupNameOrdinal),
232→                            OrganizationId = this.ReadString(reader, organizationIdOrdinal),
233→                            OrganizationName = this.ReadString(reader, organizationNameOrdinal),
234→                            DivisionId = this.ReadString(reader, divisionIdOrdinal),
235→                            DivisionName = this.ReadString(reader, divisionNameOrdinal),
236→                        };
237→
238→                        // Always key by the native ServiceId for backward compatibility.
239→                        results[id] = node;
240→
241→                        // Also key by any hierarchy ancestor ID that the caller asked for.
242→                        // This lets a caller who passed an OrganizationId (or ServiceGroupId etc.)
243→                        // find the result via hierarchyResults.TryGetValue(inputId).
244→                        var teamGroupId = this.ReadString(reader, teamGroupIdOrdinal);
245→                        foreach (var hierarchyId in new[]
246→                        {
247→                            teamGroupId,
248→                            node.ServiceGroupId,
249→                            node.OrganizationId,
250→                            node.DivisionId,
251→                        })
252→                        {
253→                            if (!string.IsNullOrWhiteSpace(hierarchyId)
254→                                && batchSet.Contains(hierarchyId.ToLowerInvariant()))
255→                            {
256→                                results[hierarchyId] = node;
257→                            }
258→                        }
259→                    }
260→                }
261→                while (results.Count == 0 && reader.NextResult());
262→
263→                this.logger.LogInformation(
264→                    "ServiceTreeKustoClient: Hierarchy query completed. Returned {ResultCount} results for {BatchCount} input IDs.",
265→                    results.Count,
266→                    batch.Count);
267→            }
268→            catch (OperationCanceledException)
269→            {
270→                throw;
271→            }
272→            catch (Exception ex)
273→            {
274→                this.logger.LogError(
275→                    ex,
276→                    "ServiceTreeKustoClient: hierarchy query failed. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, BatchCount={BatchCount}.",
277→                    this.kustoOptions.ClusterUri,
278→                    this.kustoOptions.Database,
279→                    this.kustoOptions.HierarchyTableName,
280→                    this.tokenCredential.GetType().Name,
281→                    batch.Count);
282→                throw;
283→            }
284→
285→            return results;
286→        }
287→
288→        private ICslQueryProvider CreateQueryProvider()
289→        {
290→            var kcsb = new KustoConnectionStringBuilder(this.kustoOptions.ClusterUri, this.kustoOptions.Database)
291→                .WithAadAzureTokenCredentialsAuthentication(this.tokenCredential);
292→            return KustoClientFactory.CreateCslQueryProvider(kcsb);
293→        }
294→
295→        private IEnumerable<IReadOnlyList<string>> SplitStringBatches(IReadOnlyList<string> ids, int batchSize)
296→        {
297→            for (int i = 0; i < ids.Count; i += batchSize)
298→            {
299→                var count = Math.Min(batchSize, ids.Count - i);
300→                var batch = new List<string>(count);
301→                for (int j = 0; j < count; j++)
302→                {
303→                    batch.Add(ids[i + j]);
304→                }
305→
306→                yield return batch;
307→            }
308→        }
309→
310→        private string ResolveTokenScope(ServiceTreeKustoOptions options)
311→        {
312→            if (!string.IsNullOrWhiteSpace(options.TokenScope))
313→            {
314→                return options.TokenScope;
315→            }
316→
317→            if (Uri.TryCreate(options.ClusterUri, UriKind.Absolute, out var uri))
318→            {
319→                return $"{uri.GetLeftPart(UriPartial.Authority)}/.default";
320→            }
321→
322→            return string.Empty;
323→        }
324→
325→        private TokenCredential ResolveTokenCredential(ICredentialFactory credentialFactory)
326→        {
327→            var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
328→            this.logger.LogInformation(
329→                "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
330→                cred.GetType().Name);
331→            return cred;
332→        }
333→
334→        private string NormalizeIdentifier(string value)
335→        {
336→            if (string.IsNullOrWhiteSpace(value))
337→            {
338→                return value;
339→            }
340→
341→            var trimmed = value.Trim();
342→            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
343→                ? trimmed
344→                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
345→        }
346→
347→        private int TryGetOrdinal(IDataReader reader, string name)
348→        {
349→            try
350→            {
351→                return reader.GetOrdinal(name);
352→            }
353→            catch (IndexOutOfRangeException)
354→            {
355→                return -1;
356→            }
357→        }
358→
359→        private string ReadString(IDataReader reader, int ordinal)
360→        {
361→            if (ordinal < 0 || reader.IsDBNull(ordinal))
362→            {
363→                return string.Empty;
364→            }
365→
366→            var value = reader.GetValue(ordinal);
367→            return value?.ToString() ?? string.Empty;
368→        }
369→    }
370→
371→#pragma warning restore CA1303
372→}
