 89→        /// <summary>
 90→        /// Creates a <see cref="TokenCredential"/> based on the specified target resource tenant and target SPI.
 91→        /// </summary>
 92→        /// <param name="targetResTenant">The target resource Azure Active Directory (AAD) tenant.</param>
 93→        /// <param name="targetSPI">The target service principal identifier (SPI).</param>
 94→        /// <returns>A <see cref="TokenCredential"/> instance.</returns>
 95→        /// <exception cref="ArgumentException">Thrown when the target tenant and environment combination is unsupported.</exception>
 96→        public static TokenCredential CreateTokenCredential(AADTenant targetResTenant = AADTenant.MSFT, TargetSPI targetSPI = TargetSPI.Auto)
 97→        {
 98→            ValidateTargetResTenant(targetResTenant);
 99→            ValidateTargetSPI(targetSPI);
100→            if (EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.Aether)
101→            {
102→                if (targetSPI == TargetSPI.Auto)
103→                {
104→                    return GetTokenCredentialFromManagedIdentities(AetherManagedIdentities, Constants.AmeGalaxyMTAppId);
105→                }
106→
107→                return GetTokenCredentialFromManagedIdentities(AetherManagedIdentities, GalaxyAmeTargetSPIToIdDict[targetSPI]);
108→            }
109→            else if (EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.Galaxy)
110→            {
111→                ManagedIdentityCredential localTenantCred;
112→                if (EnvironmentProperties.CurrentEnvironmentMode == EnvironmentMode.Production)
113→                {
114→                    localTenantCred = new ManagedIdentityCredential(GalaxyProdManagedIdentities.First());
115→                }
116→                else if (EnvironmentProperties.CurrentEnvironmentMode == EnvironmentMode.Staging)
117→                {
118→                    localTenantCred = new ManagedIdentityCredential(GalaxyIntManagedIdentities.First());
119→                }
120→                else
121→                {
122→                    throw new Exception("In AP, Current Environment is Galaxy, EnvironmentMode can either be Production or Development");
123→                }
124→
125→                if (targetResTenant == AADTenant.PME)
126→                {
127→                    return localTenantCred;
128→                }
129→                else
130→                {
131→                    if (targetSPI == TargetSPI.Auto)
132→                    {
133→                        return new FederatedApplicationCredential(localTenantCred, Constants.MsftTenantId, Constants.PmeGalaxyMTAppId);
134→                    }
135→
136→                    return new FederatedApplicationCredential(localTenantCred, Constants.MsftTenantId, GalaxyPmeTargetSPIToIdDict[targetSPI]);
137→                }
138→            }
139→            else if (EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.EQ)
140→            {
141→                if (EnvironmentProperties.CurrentEnvironmentMode == EnvironmentMode.Production || EnvironmentProperties.CurrentEnvironmentMode == EnvironmentMode.Staging)
142→                {
143→                    if (targetSPI == TargetSPI.Auto)
144→                    {
145→                        return new FederatedApplicationCredential(Constants.MsftTenantId, EqManagedIdentities.First(), Constants.PmeEqMTAppId);
146→                    }
147→
148→                    return new FederatedApplicationCredential(Constants.MsftTenantId, EqManagedIdentities.First(), EqPmeTargetSPIToIdDict[targetSPI]);
149→                }
150→                else
151→                {
152→                    throw new Exception("In AP, Current Environment is EQ, EnvironmentMode can either be Production or Development");
153→                }
154→            }
155→            else if (EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.Starlite)
156→            {
157→                if (EnvironmentProperties.CurrentEnvironmentMode == EnvironmentMode.Production || EnvironmentProperties.CurrentEnvironmentMode == EnvironmentMode.Staging)
158→                {
159→                    return new ManagedIdentityCredential(StarliteManagedIdentities.First());
160→                }
161→                else
162→                {
163→                    throw new Exception("In AP, Current Environment is Starlite, EnvironmentMode can either be Production or Development");
164→                }
165→            }
166→            else if (EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.DevBox)
167→            {
168→                return new DefaultAzureCredential();
169→            }
170→            else
171→            {
