180→        /// <exception cref="ArgumentException">Thrown when the target tenant and environment combination is unsupported.</exception>
181→        private static void ValidateTargetResTenant(AADTenant targetResTenant)
182→        {
183→            if (targetResTenant != AADTenant.MSFT && EnvironmentProperties.CurrentEnvironmentType != EnvironmentType.Galaxy)
184→            {
185→                throw new ArgumentException("Unsupported target tenant and environment combination");
186→            }
187→        }
188→
189→        /// <summary>
190→        /// Validates the target service principal identifier (SPI).
191→        /// </summary>
192→        /// <param name="targetSPI">The target SPI.</param>
193→        /// <exception cref="ArgumentException">Thrown when the target SPI and environment combination is unsupported.</exception>
194→        private static void ValidateTargetSPI(TargetSPI targetSPI)
195→        {
196→            if (targetSPI == TargetSPI.Auto)
197→            {
198→                return;
199→            }
200→
201→            if ((EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.Aether && !GalaxyAmeTargetSPIToIdDict.ContainsKey(targetSPI)) ||
202→                (EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.Galaxy && !GalaxyPmeTargetSPIToIdDict.ContainsKey(targetSPI)) ||
203→                (EnvironmentProperties.CurrentEnvironmentType == EnvironmentType.EQ && !EqPmeTargetSPIToIdDict.ContainsKey(targetSPI)))
204→            {
