211→        /// </summary>
212→        /// <param name="tenantId">The tenant ID.</param>
213→        /// <param name="mi">The managed identity.</param>
214→        /// <param name="appId">The application ID.</param>
215→        /// <returns>A <see cref="TokenCredential"/> instance.</returns>
