  7→namespace SecretManager.Lib
  8→{
  9→    using System;
 10→    using System.Collections.Generic;
 11→    using System.Linq;
 12→    using System.Threading.Tasks;
 13→    using Azure.Identity;
 14→    using SecretManager.Interface;
 15→
 16→    /// <summary>
 17→    /// Provides functionality to manage secrets using a two-step process involving an intermediary Key Vault.
 18→    /// </summary>
 19→    public class TwoStepSecretManager : ISecretManager
 20→    {
 21→        /// <summary>
 22→        /// The Key Vault secret manager.
 23→        /// </summary>
 24→        private readonly KeyvaultSecretManager secretManager;
 25→
 26→        /// <summary>
 27→        /// Initializes a new instance of the <see cref="TwoStepSecretManager"/> class.
 28→        /// This class will use a key vault in PME to get an application secret and use the application secret to access the Microsoft tenant key vault.
 29→        /// </summary>
 30→        /// <param name="proxyKeyVaultUrl">The URL of the intermediary Key Vault (AME/PME).</param>
 31→        /// <param name="secretName">The name of the secret saved in the intermediary Key Vault (AME/PME), its value is the password for the final Key Vault.</param>
 32→        /// <param name="clientId">The client ID.</param>
 33→        /// <param name="clientTenantId">The client tenant ID.</param>
 34→        /// <param name="microsoftKeyvaultUrl">The URL of the Microsoft tenant Key Vault (final Key Vault).</param>
 35→        /// <param name="managedIdentities">The managed identities to try consecutively for accessing the intermediary Key Vault.</param>
 36→        public TwoStepSecretManager(
 37→            string proxyKeyVaultUrl,
 38→            string secretName,
 39→            string clientId,
 40→            string clientTenantId,
 41→            string microsoftKeyvaultUrl,
 42→            IEnumerable<string> managedIdentities = null)
 43→        {
 44→            string clientIdSecret = null;
 45→            if (managedIdentities != null && managedIdentities.Any())
 46→            {
 47→                clientIdSecret = this.GetSecretByMITrials(proxyKeyVaultUrl, secretName, managedIdentities);
 48→            }
 49→            else
 50→            {
 51→                var proxySecretManager = new KeyvaultSecretManager(proxyKeyVaultUrl, new DefaultAzureCredential());
 52→                clientIdSecret = proxySecretManager.GetSecretAsync(secretName).ConfigureAwait(false).GetAwaiter().GetResult();
 53→            }
 54→
 55→            this.secretManager = new KeyvaultSecretManager(microsoftKeyvaultUrl, new ClientSecretCredential(clientTenantId, clientId, clientIdSecret));
 56→        }
 57→
 58→        /// <summary>
 59→        /// Asynchronously retrieves a secret from the Key Vault.
 60→        /// </summary>
 61→        /// <param name="secretName">The name of the secret to retrieve.</param>
 62→        /// <returns>A task that represents the asynchronous operation. The task result contains the secret value.</returns>
 63→        public Task<string> GetSecretAsync(string secretName)
 64→        {
 65→            return this.secretManager.GetSecretAsync(secretName);
 66→        }
 67→
 68→        /// <summary>
 69→        /// Consecutively retries the given managed identities until it succeeds in accessing the given secret.
 70→        /// </summary>
 71→        /// <param name="keyVaultUrl">The URL of the Key Vault (AME/PME).</param>
 72→        /// <param name="secretName">The name of the secret.</param>
 73→        /// <param name="managedIdentities">The managed identities to try consecutively for accessing the intermediary Key Vault.</param>
 74→        /// <returns>The found secret.</returns>
 75→        /// <exception cref="ArgumentException">Thrown when <paramref name="managedIdentities"/> is empty.</exception>
 76→        /// <exception cref="AggregateException">Thrown when all managed identity trials fail.</exception>
 77→        private string GetSecretByMITrials(string keyVaultUrl, string secretName, IEnumerable<string> managedIdentities)
 78→        {
 79→            if (!managedIdentities.Any())
 80→            {
 81→                throw new ArgumentException("managedIdentities must not be empty");
 82→            }
 83→
 84→            // Check for a working managed identity
 85→            string secretValue = null;
 86→            var secretGetExceptions = new List<Exception>();
 87→            foreach (string mi in managedIdentities)
 88→            {
 89→                try
 90→                {
 91→                    var credential = new DefaultAzureCredential(new DefaultAzureCredentialOptions { ManagedIdentityClientId = mi });
 92→                    var secretMgr = new KeyvaultSecretManager(keyVaultUrl, credential);
 93→                    secretValue = secretMgr.GetSecretAsync(secretName).ConfigureAwait(false).GetAwaiter().GetResult();
 94→                    break;
 95→                }
 96→                catch (Exception ex)
 97→                {
 98→                    secretGetExceptions.Add(ex);
 99→                }
100→            }
101→
102→            if (secretValue == null)
103→            {
104→                throw new AggregateException(secretGetExceptions);
105→            }
106→
107→            return secretValue;
108→        }
109→    }
110→}
